INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00159', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲將其所有之A地與其上興建之B屋，及另一塊C地及其上興建之D屋，一併出售於乙，但因 甲尚有物品置於B屋內待處置，故甲乙間就A地與B屋之買賣，乃先為所有權移轉登記，但尚 未交付；而C地與D屋部分，則因乙急需使用，故甲乙間就C地與D屋之買賣，先為交付，但 尚未辦理所有權移轉登記。嗣後乙工作升遷，外派至國外，因工作忙碌，乙未積極向甲催促A地 與B屋之交付及C地與D屋之所有權移轉登記。事經15年後，下列敘述何者錯誤？', '["乙依買賣契約請求甲履行A地與B屋交付之債權，甲得抗辯已逾15年時效，依民法第125條 主張時效抗辯", "乙請求甲返還A地與B屋，甲因已將A地與B屋移轉登記，故其繼續占有，成為無權占有， 甲應予返還", "乙依買賣契約請求甲為C地與D屋所有權移轉登記，甲得抗辯已逾15年時效，依民法第125 條主張時效抗辯", "甲依民法第 179 條規定請求乙返還 C 地與 D 屋占有，乙得抗辯基於買賣契約成立之債權仍然 存在，為其占有之正當權源，不構成不當得利，而拒絕返還占有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00160', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列何種請求權之消滅時效期間並非二年？', '["商人所供給商品之代價", "旅店之住宿費", "承攬人之報酬", "借款之每月月息"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00161', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列何者是依民法第 3 條第 1 項有關文字使用之準則規定：「依法律之規定，有使用文字之必要 者」之情形？', '["買賣契約", "委任契約", "承攬契約", "人事保證契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00162', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '依民法規定，關於外國法人之敘述，下列何者錯誤？', '["外國法人，除依法律規定外，不認許其成立", "經認許成立之外國法人之權利能力，於法令限制內，與同類之本國法人有同一權利能力", "尚未經認許成立之外國法人，法人之代表人無法以法人名義與他人成立契約，僅得以自己名義 為法人與他人成立契約", "外國法人與本國法人同，其類型包含社團和財團"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00163', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於表見代理與無權代理，下列敘述何者錯誤？', '["關於表見代理，如其相對人不主張適用表見代理者，仍應適用狹義無權代理", "事實行為亦得成立表見代理", "相對人得對無權代理人請求損害賠償者，須相對人自己屬於善意，亦即於無權代理行為成立時， 對於無權代理並不知情", "有關民法第110條之賠償範圍，相對人得請求信賴利益之損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00164', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲蛋商向乙蛋雞場訂購100箱雞蛋，預定二週後交貨，甲已先給付價金新臺幣5萬元。豈料該蛋 雞場遭受H5N2高病原性禽流感危害，整場雞隻遭到全面撲殺，乙因此無法如期給付。關於給付 不能之敘述，下列何者錯誤？', '["蛋雞場遭受禽流感危害，雞隻遭到全面撲殺，乃屬於不可歸責雙方當事人所致之給付不能", "由甲負擔給付不能時之給付危險", "由乙負擔給付不能時之價金危險", "由於甲負擔給付危險，因此乙無須返還甲已支付之5萬元價金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00165', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲乙係鄰居，某日乙外出旅遊，家中無人，因電線走火引起火災。甲為撲滅火源，致乙家中之電 視浸水而受有損害，且甲因此受傷。下列敘述何者錯誤？', '["甲之救火行為係未受委任，亦無義務，而為他人管理事務", "甲之救火行為係利於乙本人，且不違反乙可得推知之意思", "甲因救火行為而受傷，得向乙請求損害賠償", "乙家中電視之損害，乙得向甲請求賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00166', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲人力仲介公司受乙工廠委託，引進外勞丙並辦理就業服務。關於僱傭之敘述，下列何者錯誤？', '["甲仲介外勞丙至乙工廠服務，僱傭關係乃存在於乙丙之間", "乙因工廠整建以致無法如期讓丙上工，丙仍須補服勞務", "丙因工廠設備故障而身體受傷，丙得向乙請求損害賠償", "丙因家人病故須返回母國，得於僱傭期限屆滿前終止契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00167', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '甲之馬戲團以猛獸表演著稱，某日表演時，因甲僱用之馴獸師乙不注意，讓猛獸逃脫至觀眾席， 因而咬傷觀眾丙。下列敘述何者正確？', '["甲為猛獸之直接占有人，故須對丙負損害賠償責任", "乙為猛獸之直接占有人，故須對丙負損害賠償責任", "甲為猛獸之占有輔助人，故無須對丙負損害賠償責任", "乙為猛獸之間接占有人，故無須對丙負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00168', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於連帶債權之敘述，下列何者正確？', '["連帶債權僅得依法律規定而生", "連帶債權之債務人須向全體債權人為全部給付", "連帶債權人中之一人受領遲延者，其他債權人亦負其責任", "連帶債權人中之一人，向債務人免除全部債務者，債權消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
